        return '0'

    digits = []
    current_n = n

    while current_n != 0:
        # We need to determine the coefficient d_i and the next quotient n_{i+1}
        # such that current_n = d_i + (-2) * next_n

        if current_n % 2 != 0:
            # If current_n is odd, we must choose d_i = 1 (since digits are {0, 1})
            d_i = 1
            # current_n - d_i must be divisible by -2
            next_n = (current_n - d_i) // (-2)
        else:
            # If current_n is even, we must choose d_i = 0
            d_i = 0
            # current_n must be divisible by -2
            next_n = current_n // (-2)

        digits.append(str(d_i))
        current_n = next_n

    # The digits were calculated from d0, d1, d2, ... (least significant first). Reverse them for the final string.
    return "".join(reversed(digits))

